const XLSX = require\('xlsx'\);
const wb = XLSX.readFile\('c:/Users/legen/OneDrive/하우스맨/건물정보및정산/02. 스타빌\(15일\)/11_정산서/02월/2026년 02월 정산서_스타빌.xlsx'\);
