    }
    console.log\('R' + \(r+1\) + ':', row.join\(' | '\)\);
  }
  // merges
  if \(ws['!merges']\) console.log\('\\n병합:', JSON.stringify\(ws['!merges'].slice\(0, 30\)\)\);
}\);
